SELECT DISTINCT "StudyInstanceUID" FROM (SELECT DISTINCT "StudyInstanceUID" FROM "IDC"."IDC_V17"."DICOM_ALL" WHERE "collection_id" = 'qin_prostate_repeatability' AND "Modality" = 'MR' AND ("SeriesDescription" ILIKE '%T2%' OR "ProtocolName" ILIKE '%T2%') AND ARRAY_CONTAINS('AXIAL'::VARIANT, "ImageType") INTERSECT SELECT DISTINCT s."StudyInstanceUID" FROM "IDC"."IDC_V17"."SEGMENTATIONS" s JOIN "IDC"."IDC_V17"."AUXILIARY_METADATA" a ON s."SOPInstanceUID" = a."SOPInstanceUID" WHERE a."collection_id" = 'qin_prostate_repeatability' AND (s."AnatomicRegion"::string ILIKE '%Peripheral zone%' OR s."SegmentedPropertyType"::string ILIKE '%Peripheral zone%'))